import React, { useState, useEffect } from 'react';
import './index.css';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ProfileModal from './components/ProfileModal';
import SettingsPanel from './components/SettingsPanel';
import LoginModal from './components/LoginModal';
import axios from 'axios';
import { themes } from './themeConfig';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [username, setUsername] = useState('游客');
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [currentTheme, setCurrentTheme] = useState('rose');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // 弹窗控制
  const [showProfile, setShowProfile] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  const theme = themes[currentTheme];

  // 加载聊天历史（登录后）
  useEffect(() => {
    if (loggedIn) {
      API.get(`/api/history?username=${username}`)
        .then(res => {
          const msgs = res.data.history.map(h => ({ sender: h.role, text: h.content }));
          setMessages(msgs);
        })
        .catch(() => {});
    }
  }, [loggedIn, username]);

  // 发送消息
  const sendMessage = async () => {
    if (!input.trim()) return;
    const userMsg = { sender: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');

    // 显示加载中
    const loadingMsg = { sender: 'assistant', text: 'loading' };
    setMessages(prev => [...prev, loadingMsg]);

    try {
      const res = await API.post('/api/chat', {
        message: input,
        username,
        logged_in: loggedIn
      });
      // 替换加载消息为真实回复
      setMessages(prev => [
        ...prev.slice(0, -1),
        { sender: 'assistant', text: res.data.reply }
      ]);
    } catch (err) {
      setMessages(prev => [
        ...prev.slice(0, -1),
        { sender: 'assistant', text: '❌ 小智老师走神了，请稍后再试~' }
      ]);
    }
  };

  // 清空对话
  const clearHistory = async () => {
    if (loggedIn) {
      try {
        await API.post(`/api/clear-history?username=${username}`);
      } catch {}
    }
    setMessages([]);
  };

  // 获取错题本
  const fetchMistakes = async () => {
    try {
      const res = await API.get('/api/mistakes');
      setMessages(prev => [...prev, { sender: 'assistant', text: res.data.mistakes }]);
    } catch (err) {
      setMessages(prev => [...prev, { sender: 'assistant', text: '❌ 加载错题本失败' }]);
    }
  };

  // 获取学习周报
  const fetchReport = async () => {
    try {
      const res = await API.get('/api/report');
      setMessages(prev => [...prev, { sender: 'assistant', text: res.data.report }]);
    } catch (err) {
      setMessages(prev => [...prev, { sender: 'assistant', text: '❌ 生成周报失败' }]);
    }
  };

  // 下载作业
  const downloadWorksheet = (answers) => {
    window.open(`http://localhost:8000/api/download-worksheet?answers=${answers}`);
  };

  // 登录成功回调
  const handleLoginSuccess = (user) => {
    setLoggedIn(true);
    setUsername(user);
    setShowLogin(false);
    setMessages([]); // 清空旧消息，下次会加载历史
  };

  // 退出登录
  const handleLogout = () => {
    setLoggedIn(false);
    setUsername('游客');
    setShowSettings(false);
    setShowProfile(false);
    setMessages([]);
  };

  return (
    <div className={`h-screen flex transition-all duration-700 ${theme.bg}`}>
      <Sidebar
        loggedIn={loggedIn}
        username={username}
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        currentTheme={currentTheme}
        setCurrentTheme={setCurrentTheme}   // 👈 这里必须加上，否则主题切换无效
        theme={theme}
        onAvatarClick={() => loggedIn ? setShowProfile(true) : setShowLogin(true)}
        onFetchMistakes={fetchMistakes}
        onFetchReport={fetchReport}
        onClearHistory={clearHistory}
        onDownloadWorksheet={downloadWorksheet}
      />
      <ChatWindow
        messages={messages}
        input={input}
        setInput={setInput}
        onSend={sendMessage}
        theme={theme}
        sidebarOpen={sidebarOpen}
      />
      {/* 弹窗 */}
      {showProfile && (
        <ProfileModal
          username={username}
          theme={theme}
          onClose={() => setShowProfile(false)}
          onOpenSettings={() => { setShowProfile(false); setShowSettings(true); }}
        />
      )}
      {showSettings && (
        <SettingsPanel
          theme={theme}
          currentTheme={currentTheme}
          setCurrentTheme={setCurrentTheme}
          onClose={() => setShowSettings(false)}
          onLogout={handleLogout}
          onSwitchAccount={() => {
            setShowSettings(false);
            setShowLogin(true);
            handleLogout();
          }}
        />
      )}
      {showLogin && (
        <LoginModal
          theme={theme}
          onClose={() => setShowLogin(false)}
          onLoginSuccess={handleLoginSuccess}
        />
      )}
    </div>
  );
}

export default App;
